        prefix_A[0] = strategy[0] * prices[0];
        base = prefix_A[0];
        for (int i = 1; i < n; i++) {
            prefix_prices[i] = prefix_prices[i-1] + prices[i];
            long long add = strategy[i] * prices[i];
            base += add;
            prefix_A[i] = prefix_A[i-1] + add;
        }
    }

    long long ans = base;

    for (int l = 0; l <= n - int_k; l++) {
        int r = l + int_k - 1;
